1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	// Base premiums for main (non-component) items. Components such as runes are
14	// priced separately via componentBasePremium and never read from this table.
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	const FIRST_INSURANCE_RATE = 0.1;
22	const CURSE_SURCHARGE_RATE = 0.5;
23	const HIGH_ENCHANTMENT_RATE = 0.3;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	const LOYALTY_THRESHOLD_YEARS = 2;
26	const LOYALTY_DISCOUNT_RATE = 0.2;
27	
28	const sum = (values: number[]): number =>
29	  values.reduce((total, value) => total + value, 0);
30	
31	// Item-specific surcharges, each a rate applied additively to the base premium
32	// when its condition holds. First insurance always applies; the rest are
33	// conditional on the item.
34	const mainItemSurchargeRates = (item: Item): number[] => [
35	  FIRST_INSURANCE_RATE,
36	  ...(item.cursed ? [CURSE_SURCHARGE_RATE] : []),
37	  ...((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
38	    ? [HIGH_ENCHANTMENT_RATE]
39	    : []),
40	];
41	
42	// The additive surcharge model: a base premium scaled by 1 plus the sum of all
43	// applicable rates. Shared by every premium path (single source of truth).
44	const applyRates = (basePremium: number, rates: number[]): number =>
45	  basePremium * (1 + sum(rates));
46	
47	// A main item's premium: its base premium with all applicable surcharge rates applied.
48	const mainItemPremium = (item: Item): number =>
49	  applyRates(BASE_PREMIUMS[item.type], mainItemSurchargeRates(item));
50	
51	const COMPONENT_TYPES = ["rune", "moonstone"];
52	const COMPONENT_BASE_PREMIUM = 25;
53	const COMPONENT_BLOCK_SIZE = 3;
54	const COMPONENT_BLOCK_PREMIUM = 60;
55	
56	const isComponent = (item: Item): boolean =>
57	  COMPONENT_TYPES.includes(item.type);
58	
59	// Base premium for `count` alike components: a block premium applies only for
60	// exactly one block's worth (3) of components; otherwise each is priced individually.
61	const componentBasePremium = (count: number): number => {
62	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
63	  return count * COMPONENT_BASE_PREMIUM;
64	};
65	
66	const countByType = (items: Item[]): Map<string, number> => {
67	  const counts = new Map<string, number>();
68	  for (const item of items) {
69	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
70	  }
71	  return counts;
72	};
73	
74	// The block rule is per-type ("alike" = same type), so price each type's count
75	// independently. componentBasePremium(count) is the raw per-type base; both the
76	// surcharged premium and the policy-wide raw base build on it.
77	const componentTypeBases = (componentItems: Item[]): number[] =>
78	  [...countByType(componentItems).values()].map(componentBasePremium);
79	
80	const componentItemsBase = (componentItems: Item[]): number =>
81	  sum(componentTypeBases(componentItems).map(withFirstInsurance));
82	
83	// Every item is treated as first insurance today, so the surcharge is applied
84	// uniformly to each base premium, using the same additive rate as main items.
85	const withFirstInsurance = (basePremium: number): number =>
86	  applyRates(basePremium, [FIRST_INSURANCE_RATE]);
87	
88	// Round up in MHPCO's favour, guarding against floating-point noise
89	// (e.g. 197.50000000001 should still round to 198, not 199).
90	const roundUpInMHPCOFavor = (amount: number): number =>
91	  Math.ceil(Number(amount.toFixed(6)));
92	
93	export const quote = (
94	  items: Item[],
95	  customer: Customer,
96	  contractIndex: number,
97	): number => {
98	  const mainItems = items.filter((item) => !isComponent(item));
99	  const componentItems = items.filter((item) => isComponent(item));
100	
101	  const mainBase = sum(mainItems.map(mainItemPremium));
102	  const componentBase = componentItemsBase(componentItems);
103	
104	  // The policy base premium is the sum of raw item base premiums (no item
105	  // surcharges); policy-wide discounts are percentages of this amount.
106	  const rawMainBase = sum(mainItems.map((item) => BASE_PREMIUMS[item.type]));
107	  const rawComponentBase = sum(componentTypeBases(componentItems));
108	  const policyBasePremium = rawMainBase + rawComponentBase;
109	
110	  const loyaltyDiscount =
111	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
112	      ? LOYALTY_DISCOUNT_RATE * policyBasePremium
113	      : 0;
114	
115	  return roundUpInMHPCOFavor(
116	    mainBase + componentBase - loyaltyDiscount + PROCESSING_FEE,
117	  );
118	};
119	
120	export const claim = (): number => {
121	  return undefined as unknown as number;
122	};
